import React, { useState } from 'react';
import Login from './pages/Login';
import FloorSelection from './pages/FloorSelection';
import RoomList from './pages/RoomList';
import RoomDetail from './pages/RoomDetail';
import AdminPanel from './pages/AdminPanel';
import ExpiryList from './pages/ExpiryList';
import Header from './components/Header';
import { ALL_ROOMS } from './data/roomsData';
import './styles/main.css';
import './styles/inventory.css';

function App() {
    const [user, setUser] = useState(null);
    const [screen, setScreen] = useState('login');
    const [selectedFloor, setSelectedFloor] = useState(null);
    const [selectedRoom, setSelectedRoom] = useState(null);
    const [rooms, setRooms] = useState(ALL_ROOMS);
    const [expiryThreshold, setExpiryThreshold] = useState(90); // Порог просрочки

    const handleLogout = () => {
        setUser(null);
        setScreen('login');
    };

    const handleSaveRoom = (updatedRoom) => {
        const newRooms = rooms.map(r => r.id === updatedRoom.id ? updatedRoom : r);
        setRooms(newRooms);
        setScreen('rooms');
    };

    if (!user) {
        return <Login onLogin={(userData) => { setUser(userData); setScreen('floors'); }} />;
    }

    return (
        <div className="app-container">
            <Header
                user={user}
                onLogout={handleLogout}
                onBack={() => setScreen(screen === 'detail' ? 'rooms' : 'floors')}
                showBack={screen !== 'floors'}
            />

            {screen === 'floors' && (
                <FloorSelection
                    onSelectFloor={(floor) => { setSelectedFloor(floor); setScreen('rooms'); }}
                    onShowExpiry={() => setScreen('expiry')}
                    onOpenAdmin={() => setScreen('admin')}
                    role={user.role}
                />
            )}

            {screen === 'rooms' && (
                <RoomList
                    floor={selectedFloor}
                    rooms={rooms}
                    onSelectRoom={(room) => { setSelectedRoom(room); setScreen('detail'); }}
                />
            )}

            {screen === 'detail' && (
                <RoomDetail
                    room={selectedRoom}
                    user={user}
                    onSave={handleSaveRoom}
                />
            )}

            {screen === 'admin' && (
                <AdminPanel
                    rooms={rooms}
                    threshold={expiryThreshold}
                    setThreshold={setExpiryThreshold}
                />
            )}

            {screen === 'expiry' && (
                <ExpiryList rooms={rooms} threshold={expiryThreshold} />
            )}
        </div>
    );
}

export default App;
